unit lipdecide;

interface

uses globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

function REALCOMPARE(A, B: real): COMPTYPE;
var
  va, vb: real;
  exp: integer;
begin
  if (A = 0) and (B = 0) then
  begin
    REALCOMPARE := EQ;
    exit;
  end;

  if A = 0 then
  begin
    if B > 0 then REALCOMPARE := LT else REALCOMPARE := GT;
    exit;
  end;

  if B = 0 then
  begin
    if A > 0 then REALCOMPARE := GT else REALCOMPARE := LT;
    exit;
  end;

  va := A;
  vb := B;
  exp := 0;

  while (abs(va) < 0.1) and (exp < 100) do
  begin
    va := va * 10;
    vb := vb * 10;
    exp := exp + 1;
  end;
  while (abs(va) >= 1.0) and (exp > -100) do
  begin
    va := va / 10;
    vb := vb / 10;
    exp := exp - 1;
  end;

  if abs(va - vb) < 0.000005 then
    REALCOMPARE := EQ
  else if va < vb then
    REALCOMPARE := LT
  else
    REALCOMPARE := GT;
end;

procedure DECIDE;
var
  i, j, k: integer;
  dist_sq: real;
  found_gt_len1: boolean;
  found_lt_len2: boolean;
  found_not_in_r1: boolean;
  found_in_r2: boolean;
  found_gt_area1: boolean;
  found_lt_area2: boolean;

  function get_dist_sq(i, j: integer): real;
  begin
    get_dist_sq := (X[i] - X[j])**2 + (Y[i] - Y[j])**2;
  end;

  function get_area(i, j, k: integer): real;
  begin
    get_area := 0.5 * abs(X[i]*(Y[j] - Y[k]) + X[j]*(Y[k] - Y[i]) + X[k]*(Y[i] - Y[j]));
  end;

  function get_angle(i, j, k: integer): real;
  var
    ux, uy, vx, vy: real;
    dot, mag_u, mag_v: real;
  begin
    ux := X[i] - X[j];
    uy := Y[i] - Y[j];
    vx := X[k] - X[j];
    vy := Y[k] - Y[j];

    dot := ux*vx + uy*vy;
    mag_u := sqrt(ux*ux + uy*uy);
    mag_v := sqrt(vx*vx + vy*vy);

    if (mag_u = 0) or (mag_v = 0) then
      get_angle := -1.0 {Undefined}
    else
      get_angle := acos(dot / (mag_u * mag_v));
  end;

  function can_contain_in_circle(i, j, k: integer; r: real): boolean;
  var
    a, b, c: real;
    d: real;
    ux, uy, vx, vy: real;
    center_x, center_y: real;
    dist_sq_to_center: real;
  begin
    { Checks if 3 points can be contained in a circle of radius r }
    { A set of 3 points is contained in a circle of radius r if:
       1. The triangle is obtuse or right: the diameter is the longest side.
       2. The triangle is acute: the circumcircle is the smallest circle. }

    a := sqrt(get_dist_sq(i, j));
    b := sqrt(get_dist_sq(j, k));
    c := sqrt(get_dist_sq(i, k));

    if (a > 2*r) or (b > 2*r) or (c > 2*r) then
    begin
      can_contain_in_circle := false;
      exit;
    end;

    { Case 1: Longest side is diameter }
    { Check if any side can be diameter and contain the 3rd point }
    { Point P is inside circle with diameter AB if angle APB >= 90 deg }
    { This is equivalent to (P-A).(P-B) <= 0 }
    if ((X[k]-X[i])*(X[k]-X[j]) + (Y[k]-Y[i])*(Y[k]-Y[j]) <= 0) and (a <= 2*r) then
    begin
      can_contain_in_circle := true;
      exit;
    end;
    if ((X[i]-X[j])*(X[i]-X[k]) + (Y[i]-Y[j])*(Y[i]-Y[k]) <= 0) and (b <= 2*r) then
    begin
      can_contain_in_circle := true;
      exit;
    end;
    if ((X[j]-X[i])*(X[j]-X[k]) + (Y[j]-Y[i])*(Y[j]-Y[k]) <= 0) and (c <= 2*r) then
    begin
      can_contain_in_circle := true;
      exit;
    end;

    { Case 2: Acute triangle, check circumradius }
    { Circumradius R = abc / (4 * Area) }
    d := 2 * get_area(i, j, k);
    if d = 0 then
    begin
      { Collinear points: check if max dist <= 2r }
      can_contain_in_circle := (max(max(a,b),c) <= 2*r);
      exit;
    end;

    if (a*b*c / (2*d) <= r) then
      can_contain_in_circle := true
    else
      can_contain_in_circle := false;
  end;

  function get_quadrant(px, py: real): integer;
  begin
    if px >= 0 then
    begin
      if py >= 0 then get_quadrant := 1 else get_quadrant := 3;
    end
    else
    begin
      if py >= 0 then get_quadrant := 2 else get_quadrant := 4;
    end;
  end;

  function max(a, b: real): real;
  begin
    if a > b then max := a else max := b;
  end;

begin
  { LIC 1 }
  CMV[1] := false;
  for i := 1 to NUMPOINTS - 1 do
    if REALCOMPARE(sqrt(get_dist_sq(i, i+1)), PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := true;
      break;
    end;

  { LIC 2 }
  CMV[2] := false;
  for i := 1 to NUMPOINTS - 2 do
    if not can_contain_in_circle(i, i+1, i+2, PARAMETERS.RADIUS1) then
    begin
      CMV[2] := true;
      break;
    end;

  { LIC 3 }
  CMV[3] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    var current_angle := get_angle(i, i+1, i+2);
    if (current_angle >= 0) then
    begin
      if (REALCOMPARE(current_angle, PI - PARAMETERS.EPSILON) = LT) or 
         (REALCOMPARE(current_angle, PI + PARAMETERS.EPSILON) = GT) then
      begin
        CMV[3] := true;
        break;
      end;
    end;
  end;

  { LIC 4 }
  CMV[4] := false;
  for i := 1 to NUMPOINTS - 2 do
    if REALCOMPARE(get_area(i, i+1, i+2), PARAMETERS.AREA1) = GT then
    begin
      CMV[4] := true;
      break;
    end;

  { LIC 5 }
  CMV[5] := false;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    var quad_count := 0;
    var q1 := false; var q2 := false; var q3 := false; var q4 := false;
    for j := i to i + PARAMETERS.Q_PTS - 1 do
    begin
      case get_quadrant(X[j], Y[j]) of
        1: q1 := true;
        2: q2 := true;
        3: q3 := true;
        4: q4 := true;
      end;
    end;
    if q1 then inc(quad_count);
    if q2 then inc(quad_count);
    if q3 then inc(quad_count);
    if q4 then inc(quad_count);

    if quad_count > PARAMETERS.QUADS then
    begin
      CMV[5] := true;
      break;
    end;
  end;

  { LIC 6 }
  CMV[6] := false;
  for i := 1 to NUMPOINTS - 1 do
    if X[i+1] - X[i] < 0 then
    begin
      CMV[6] := true;
      break;
    end;

  { LIC 7 }
  CMV[7] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      var j := i + PARAMETERS.N_PTS - 1;
      var dist_met := false;
      if (X[i] = X[j]) and (Y[i] = Y[j]) then
      begin
        for k := i + 1 to j - 1 do
          if REALCOMPARE(sqrt(get_dist_sq(i, k)), PARAMETERS.DIST) = GT then
          begin
            dist_met := true;
            break;
          end;
      end
      else
      begin
        for k := i + 1 to j - 1 do
        begin
          var a := Y[j] - Y[i];
          var b := X[i] - X[j];
          var c := (X[j]*Y[i]) - (X[i]*Y[j]);
          var dist := abs(a*X[k] + b*Y[k] + c) / sqrt(a*a + b*b);
          if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
          begin
            dist_met := true;
            break;
          end;
        end;
      end;
      if dist_met then
      begin
        CMV[7] := true;
        break;
      end;
    end;
  end;

  { LIC 8 }
  CMV[8] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      if REALCOMPARE(sqrt(get_dist_sq(i, i + PARAMETERS.K_PTS + 1)), PARAMETERS.LENGTH1) = GT then
      begin
        CMV[8] := true;
        break;
      end;
    end;
  end;

  { LIC 9 }
  CMV[9] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2) do
    begin
      var j := i + PARAMETERS.A_PTS + 1;
      var k := j + PARAMETERS.B_PTS + 1;
      if not can_contain_in_circle(i, j, k, PARAMETERS.RADIUS1) then
      begin
        CMV[9] := true;
        break;
      end;
    end;
  end;

  { LIC 10 }
  CMV[10] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - (PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2) do
    begin
      var j := i + PARAMETERS.C_PTS + 1;
      var k := j + PARAMETERS.D_PTS + 1;
      var angle := get_angle(i, j, k);
      if (angle >= 0) then
      begin
        if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or 
           (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        begin
          CMV[10] := true;
          break;
        end;
      end;
    end;
  end;

  { LIC 11 }
  CMV[11] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2) do
    begin
      var j := i + PARAMETERS.E_PTS + 1;
      var k := j + PARAMETERS.F_PTS + 1;
      if REALCOMPARE(get_area(i, j, k), PARAMETERS.AREA1) = GT then
      begin
        CMV[11] := true;
        break;
      end;
    end;
  end;

  { LIC 12 }
  CMV[12] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    begin
      var j := i + PARAMETERS.G_PTS + 1;
      if X[j] - X[i] < 0 then
      begin
        CMV[12] := true;
        break;
      end;
    end;
  end;

  { LIC 13 }
  CMV[13] := false;
  if NUMPOINTS >= 3 then
  begin
    found_gt_len1 := false;
    found_lt_len2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      var d := sqrt(get_dist_sq(i, i + PARAMETERS.K_PTS + 1));
      if REALCOMPARE(d, PARAMETERS.LENGTH1) = GT then found_gt_len1 := true;
      if REALCOMPARE(d, PARAMETERS.LENGTH2) = LT then found_lt_len2 := true;
    end;
    if found_gt_len1 and found_lt_len2 then CMV[13] := true;
  end;

  { LIC 14 }
  CMV[14] := false;
  if NUMPOINTS >= 5 then
  begin
    found_not_in_r1 := false;
    found_in_r2 := false;
    for i := 1 to NUMPOINTS - (PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2) do
    begin
      var j := i + PARAMETERS.A_PTS + 1;
      var k := j + PARAMETERS.B_PTS + 1;
      if not can_contain_in_circle(i, j, k, PARAMETERS.RADIUS1) then found_not_in_r1 := true;
      if can_contain_in_circle(i, j, k, PARAMETERS.RADIUS2) then found_in_r2 := true;
    end;
    if found_not_in_r1 and found_in_r2 then CMV[14] := true;
  end;

  { LIC 15 }
  CMV[15] := false;
  if NUMPOINTS >= 5 then
  begin
    found_gt_area1 := false;
    found_lt_area2 := false;
    for i := 1 to NUMPOINTS - (PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2) do
    begin
      var j := i + PARAMETERS.E_PTS + 1;
      var k := j + PARAMETERS.F_PTS + 1;
      var area := get_area(i, j, k);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then found_gt_area1 := true;
      if REALCOMPARE(area, PARAMETERS.AREA2) = LT then found_lt_area2 := true;
    end;
    if found_gt_area1 and found_lt_area2 then CMV[15] := true;
  end;

  { PUM }
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then continue;
      case LCM[i, j] of
        NOTUSED: PUM[i, j] := true;
        ANDD: PUM[i, j] := CMV[i] and CMV[j];
        ORR: PUM[i, j] := CMV[i] or CMV[j];
      end;
    end;
  end;

  { FUV }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
    begin
      FUV[i] := true;
    end
    else
    begin
      var all_true := true;
      for j := 1 to 15 do
        if not PUM[i, j] then
        begin
          all_true := false;
          break;
        end;
      FUV[i] := all_true;
    end;
  end;

  { LAUNCH }
  LAUNCH := true;
  for i := 1 to 15 do
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
end;

end.
